def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.log1p(cap) * 30
        fluctuation = 0.0
        scale_factor = (cap + 1) ** 0.7
        if usage > 5:
            base_priority += 7500 * np.power(usage, 1.3)
            if cap > 12:
                base_priority += 150 * np.cbrt(cap) + 50 * np.cos(cap * 1.8)
            else:
                base_priority -= 50 * usage + 200 * np.sin(cap * 3)
            for i in range(1, 7):
                fluctuation += ((-1)**(i)) * np.sin(usage * np.pi * i * 0.9) * 25 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 3000 * delta ** 2 + 350 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.1)) * 30 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 2100 * (usage - 3)**1.9
            for k in range(1, 13):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1500 * (usage - 2)**2.2
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 22 / m
                    if m % 6 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 14 and usage > 2.7:
                        fluctuation += 18
            if cap % 1.7 < 0.4:
                base_priority += 40 * np.cos(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 1000 * (usage - 1) ** 3.3
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 28 / n
                    if n % 5 == 2:
                        fluctuation -= 1.5 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 1)
                    if n == 17 and usage > 1.8:
                        fluctuation += 22
            if cap % 2.1 < 0.35:
                base_priority += 38 * np.sin(cap * 3.2)
        elif 0.6 < usage <= 1:
            base_priority += 160 * (1 - usage)
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 9 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.8:
                base_priority += np.log1p(cap * 22) * 40
            else:
                base_priority += (cap % 4) * 28
        else:
            base_priority += 300 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 8) - 0.2) * 16 / p
                if usage < 0.012 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 380
            elif cap < 1.0:
                base_priority += np.log1p(cap * 28) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.18:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1400) % (r + 5) == 0:
                    priority += r * 9
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 45
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 110
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 21 == 0:
            proximity += 18
        if int(cap * 1000) % 27 == 0:
            proximity -= 14
        if int(cap * 200) % 11 == 0:
            proximity += 16
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.018:
                proximity += 22 / u
            elif diff < 0.045:
                proximity += 13 / u
            else:
                proximity -= 5 / u
        for v in range(1, 9):
            mod_chk = int(cap * 1800) % (v + 10)
            if mod_chk == 0:
                proximity += v * 6
            elif mod_chk == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1800) % (w + 7)
            if mod_chk == 0:
                proximity += 12 * w
            elif mod_chk == 4:
                proximity -= 9 * w
        priority += proximity
        if usage < 0.004:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.96:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 45
            if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                priority += 65
            for z in range(1, 7):
                if (int(cap * 700) % (z + 10) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
